module fsm
(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

always @(IN or CLK or RST) begin
    if (RST) begin
        MATCH <= 1'b0;
    end else begin
        MATCH <= 1'b0;
    end
end
always @(posedge CLK or posedge RST) begin
    if (RST) begin
        MATCH <= 1'b0;
    end else begin
        case (state)
            S0: begin
                if (IN) begin
                    next_state <= S1;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S0;
                    MATCH <= 1'b0;
                end
            end
            S1: begin
                if (IN) begin
                    next_state <= S1;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S3;
                    MATCH <= 1'b0;
                end
            end
            S2: begin
                if (IN) begin
                    next_state <= S7;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S5;
                    MATCH <= 1'b0;
                end
            end
            S3: begin
                if (IN) begin
                    next_state <= S4;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S0;
                    MATCH <= 1'b0;
                end
            end
            S4: begin
                if (IN) begin
                    next_state <= S1;
                    MATCH <= 1'b1;
                end else begin
                    next_state <= S0;
                    MATCH <= 1'b0;
                end
            end
            S5: begin
                if (IN) begin
                    next_state <= S7;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S6;
                    MATCH <= 1'b0;
                end
            end
            S6: begin
                if (IN) begin
                    next_state <= S7;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S0;
                    MATCH <= 1'b0;
                end
            end
            S7: begin
                if (IN) begin
                    next_state <= S1;
                    MATCH <= 1'b0;
                end else begin
                    next_state <= S5;
                    MATCH <= 1'b0;
                end
            end
            default: begin
                next_state <= S0;
                MATCH <= 1'b0;
            end
        endcase
    end
end

always @(state or IN) begin
    case (state)
        S0: begin
            if (IN) begin
                next_state <= S1;
                MATCH <= 1'b0;
            end else begin
                next_state <= S0;
                MATCH <= 1'b0;
            end
        end
        S1: begin
            if (IN) begin
                next_state <= S1;
                MATCH <= 1'b0;
            end else begin
                next_state <= S3;
                MATCH <= 1'b0;
            end
        end
        S2: begin
            if (IN) begin
                next_state <= S7;
                MATCH <= 1'b0;
            end else begin
                next_state <= S5;
                MATCH <= 1'b0;
            end
        end
        S3: begin
            if (IN) begin
                next_state <= S4;
                MATCH <= 1'b0;
            end else begin
                next_state <= S0;
                MATCH <= 1'b0;
            end
        end
        S4: begin
            if (IN) begin
                next_state <= S1;
                MATCH <= 1'b1;
            end else begin
                next_state <= S0;
                MATCH <= 1'b0;
            end
        end
        S5: begin
            if (IN) begin
                next_state <= S7;
                MATCH <= 1'b0;
            end else begin
                next_state <= S6;
                MATCH <= 1'b0;
            end
        end
        S6: begin
            if (IN) begin
                next_state <= S7;
                MATCH <= 1'b0;
            end else begin
                next_state <= S0;
                MATCH <= 1'b0;
            end
        end
        S7: begin
            if (IN) begin
                next_state <= S1;
                MATCH <= 1'b0;
            end else begin
                next_state <= S5;
                MATCH <= 1'b0;
            end
        end
        default: begin
            next_state <= S0;
            MATCH <= 1'b0;
        end
    endcase
end

endmodule
